import { Col, DatePicker, InputNumber, Row } from "antd"
import dayjs from "dayjs"
import { useEffect, useMemo, useState } from "react"
import { useSelector } from "react-redux"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import SvgIcon from "src/components/SvgIcon"
import TableCustom from "src/components/Table/CustomTable"
import TitleCustom from "src/components/TitleCustom"
import { hideOnSinglePage, SYSTEM_KEY } from "src/constants/constants"
import { useBadgeCounts } from "src/hooks/useBadgeCounts"
import { getListComboByKey } from "src/lib/utils"
import FeeManagement from "src/services/FeeManagement"
import FeeInternalModal from "./modal/FeeInternalModal"
import TransactionDetailModal from "./modal/TransactionDetailModal"

const ListExpenditure = () => {
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState([])
  const [openModalInsertInternal, setOpenModalInsertInternal] = useState(false)
  const [searchText, setSearchText] = useState("")
  const [fromDate, setFromDate] = useState(null)
  const [fromMoney, setFromMoney] = useState(null)
  const [toMoney, setToMoney] = useState(null)
  const [toDate, setToDate] = useState(dayjs().add(1, "day"))
  const [selectedRecord, setSelectedRecord] = useState(null)
  const [statusFilter, setStatusFilter] = useState(null)
  const { RangePicker } = DatePicker

  const [pagination, setPagination] = useState({
    PageSize: 20,
    CurrentPage: 1,
  })

  const { listSystemKey } = useSelector(state => state.appGlobal)
  const { badgeCounts } = useBadgeCounts()
  const pendingRequestsCount = badgeCounts.incomeAndExpenditureRequest || 0

  const feeStatusList = useMemo(() => {
    const list = getListComboByKey(SYSTEM_KEY.FEE_STATUS, listSystemKey)
    return list || []
  }, [listSystemKey])

  const columns = [
    {
      title: "STT",
      dataIndex: "index",
      key: "index",
      width: 70,
      align: "center",
      render: (val, record, idx) => (
        <div className="text-center">
          {idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1)}
        </div>
      ),
    },
    {
      title: "Mã Số",
      dataIndex: "FeeCode",
      key: "FeeCode",
      align: "center",
    },
    {
      title: "Mô tả",
      dataIndex: "Note",
      key: "Note",
      align: "center",
    },
    {
      title: "Ngày Tạo",
      dataIndex: "CreateDate",
      key: "CreateDate",
      align: "center",
      width: 160,
      render: value => {
        // Kiểm tra giá trị đặc biệt "0001-01-01..." => bỏ qua hoặc thay thế
        if (!value || value.startsWith("0001-01-01")) {
          return <span style={{ color: "#999" }}>--</span>
        }
        return dayjs(value).format("DD/MM/YYYY")
      },
    },
    {
      title: "Chi hội",
      align: "center",
      render: (_, record) => {
        if (record.FeeType === 2) {
          return record.ReceiverName || "-"
        } else if (record.FeeType === 1) {
          return record.SenderName || "-"
        }
        return "-"
      },
    },
    {
      title: "Số Tiền Chi (VNĐ)",
      dataIndex: "Amount",
      key: "Amount",
      align: "right",
      width: 170,
      render: (val, record) => {
        const type = record.FeeType // 1: thu, 2: chi, 3: donate
        let color = "green"
        let sign = "+"

        if (type === 2) {
          // Chi
          color = "red"
          sign = "-"
        } else if (type === 1 || type === 3) {
          // Thu hoặc Donate
          color = "green"
          sign = "+"
        }

        return (
          <div
            style={{
              color: color,
              fontWeight: "600",
              fontSize: "16px",
            }}
          >
            {sign} {formatCurrency(val)} đ
          </div>
        )
      },
    },
    {
      title: "Trạng thái",
      key: "FeeStatus",
      align: "center",
      width: 167,
      render: (_, record) => {
        const { FeeStatus } = record

        let status = ""
        let color = ""

        switch (FeeStatus) {
          case 3:
            status = "Từ chối"
            color = "#f5222d"
            break
          case 1:
            status = "Đang xử lý"
            color = "#ffc069"
            break
        }

        return (
          <div className="text-center">
            <div
              style={{
                color,
                fontWeight: 600,
                fontSize: 16,
              }}
            >
              {status}
            </div>

            {/* Các hành động nếu đang xử lý */}
            {FeeStatus === 1 && (
              <FloatActionWrapper
                size="small"
                className="float-action__wrapper"
              >
                {listData?.ButtonShow?.IsUpdateStatus && (
                  <ButtonCircle
                    title="Duyệt"
                    iconName="check-circle"
                    style={{ background: "#EDF6FC" }}
                    onClick={e => {
                      e.stopPropagation()
                      CB1({
                        title:
                          "Bạn có chắc chắn muốn duyệt khoản phí này không?",
                        icon: "signSuccess",
                        okText: "Đồng ý",
                        onOk: close => handleApprove(record, close),
                      })
                    }}
                  />
                )}

                {listData?.ButtonShow?.IsUpdateStatus && (
                  <ButtonCircle
                    title="Từ chối"
                    iconName="cancel"
                    style={{ background: "#EDF6FC" }}
                    onClick={e => {
                      e.stopPropagation()
                      CB1({
                        title:
                          "Bạn có chắc chắn muốn từ chối khoản phí này không?",
                        icon: "cancel",
                        okText: "Từ chối",
                        onOk: close => handleReject(record, close),
                      })
                    }}
                  />
                )}

                {listData?.ButtonShow?.IsDelete && (
                  <ButtonCircle
                    title="Xóa"
                    iconName="delete-outline"
                    style={{ background: "#FFF0F0" }}
                    onClick={e => {
                      e.stopPropagation()
                      CB1({
                        title: "Bạn có chắc chắn muốn xóa bản ghi này không?",
                        icon: "warning",
                        okText: "Xóa",
                        onOk: async close => handleDelete(record, close),
                      })
                    }}
                  />
                )}
              </FloatActionWrapper>
            )}
          </div>
        )
      },
    },
  ]

  const handleApprove = async (record, close) => {
    try {
      setLoading(true)
      const res = await FeeManagement.postChangeFeeStatus({
        feeTransactionID: record.FeeTransactionID,
        feeStatus: 2,
      })
      if (res?.isOk) {
        notice({ msg: "Khoản phí đã được duyệt." })
        await getList()
      } else {
        notice({ msg: "Duyệt khoản phí thất bại!", isSuccess: false })
      }
    } catch (error) {
      console.error("Duyệt lỗi:", error)
      notice({ msg: "Có lỗi xảy ra khi duyệt!", isSuccess: false })
    } finally {
      setLoading(false)
      close()
    }
  }

  const handleReject = async (record, close) => {
    try {
      setLoading(true)
      const res = await FeeManagement.postChangeFeeStatus({
        feeTransactionID: record.FeeTransactionID,
        feeStatus: 3,
      })
      if (res?.isOk) {
        notice({ msg: "Khoản phí đã bị từ chối." })
        await getList()
      } else {
        notice({ msg: "Từ chối khoản phí thất bại!", isSuccess: false })
      }
    } catch (error) {
      console.error("Từ chối lỗi:", error)
      notice({ msg: "Có lỗi xảy ra khi từ chối!", isSuccess: false })
    } finally {
      setLoading(false)
      close()
    }
  }

  const handleDelete = async (record, close) => {
    try {
      setLoading(true)
      const res = await FeeManagement.deleteFeeTransaction({
        FeeTransactionID: record.FeeTransactionID,
      })

      if (res?.isOk) {
        notice({ msg: "Xóa giao dịch thành công." })
        await getList()
      } else {
        console.error("Chi tiết lỗi:", res)
        notice({
          msg: res?.messages?.[0] || "Xóa giao dịch thất bại!",
          isSuccess: false,
        })
      }
    } catch (error) {
      console.error("Lỗi khi xóa giao dịch:", error)
      notice({ msg: "Đã xảy ra lỗi khi xóa giao dịch!", isSuccess: false })
    } finally {
      setLoading(false)
      close()
    }
  }

  const handleViewDetail = record => {
    setSelectedRecord(record)
  }

  const formatCurrency = value => {
    if (typeof value !== "number") value = Number(value)
    return value.toLocaleString("vi-VN")
  }

  const handleSearch = value => {
    setSearchText(value)
    setPagination(prev => ({ ...prev, CurrentPage: 1 }))
  }

  const getList = async () => {
    try {
      setLoading(true)

      const filters = {
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
        TextSearch: searchText,
        TransactionType: 1,
        FeeStatus: 0,
      }

      if (statusFilter !== null && statusFilter !== undefined) {
        filters.FeeStatus = statusFilter
      }

      if (fromDate) filters.StartDate = fromDate.format("YYYY/MM/DD")
      if (toDate) filters.EndDate = toDate.add(1, "day").format("YYYY/MM/DD")
      if (fromMoney) filters.FromMoney = fromMoney
      if (toMoney) filters.ToMoney = toMoney

      const res = await FeeManagement.getFeeTransactionList(filters)

      if (res?.isError) return
      setListData(res?.Object)
    } catch (error) {
      console.log("error>>getList:", error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getList()
  }, [
    pagination,
    searchText,
    fromDate,
    toDate,
    fromMoney,
    toMoney,
    statusFilter,
  ])

  return (
    <SpinCustom spinning={loading}>
      <Row gutter={[16, 16]} align="middle" style={{ marginBottom: 16 }}>
        <Col span={24}>
          <TitleCustom className={"d-flex-sb"}>
            {
              <div
                style={{
                  position: "relative",
                  display: "flex",
                }}
              >
                <span>Phê duyệt thu chi ({pendingRequestsCount})</span>
              </div>
            }

            <div className="d-flex-end">
              <ButtonCustom
                icon={<SvgIcon name="uploadVBMIcon" />}
                onClick={() => {}}
                className="mr-8"
              >
                Xuất Excel
              </ButtonCustom>

              <ButtonCustom
                type="primary"
                icon={<SvgIcon name="add-primary" />}
                className="btn-hover-shadow"
                onClick={() => setOpenModalInsertInternal(true)}
              >
                Tạo khoản chi nội bộ
              </ButtonCustom>
            </div>
          </TitleCustom>
        </Col>
        <Col span={6}>
          <InputCustom
            type="search"
            placeholder="Tìm kiếm theo hội"
            allowClear
            onSearch={handleSearch}
          />
        </Col>

        {/* Từ ngày */}
        <Col span={8}>
          <RangePicker
            style={{ width: "100%" }}
            format="DD/MM/YYYY"
            placeholder={["Từ ngày", "Đến ngày"]}
            value={fromDate && toDate ? [fromDate, toDate] : []}
            onChange={dates => {
              if (dates) {
                setFromDate(dates[0])
                setToDate(dates[1])
              } else {
                setFromDate(null)
                setToDate(null)
              }
              setPagination(prev => ({ ...prev, CurrentPage: 1 }))
            }}
          />
        </Col>

        {/* Lọc theo số tiền từ */}
        <Col span={3}>
          <InputNumber
            allowClear
            style={{ width: "100%" }}
            placeholder="≥ Số tiền"
            min={0}
            value={fromMoney}
            onChange={value => {
              setFromMoney(value)
              setPagination(prev => ({ ...prev, CurrentPage: 1 }))
            }}
          />
        </Col>

        {/* Lọc theo số tiền đến */}
        <Col span={3}>
          <InputNumber
            allowClear
            style={{ width: "100%" }}
            placeholder="≤ Số tiền"
            min={0}
            value={toMoney}
            onChange={value => {
              setToMoney(value)
              setPagination(prev => ({ ...prev, CurrentPage: 1 }))
            }}
          />
        </Col>

        {/* Lọc theo trạng thái */}
        <Col span={4}>
          <SelectCustom
            allowClear
            style={{ width: "100%" }}
            placeholder="Trạng thái"
            value={statusFilter}
            onChange={value => {
              setStatusFilter(value)
              setPagination(prev => ({ ...prev, CurrentPage: 1 }))
            }}
          >
            {feeStatusList
              ?.filter(item => item.CodeKey !== "FEE_STATUS_ACCEPT")
              ?.map(item => (
                <SelectCustom.Option key={item.CodeKey} value={item.CodeValue}>
                  {item.Description}
                </SelectCustom.Option>
              ))}
          </SelectCustom>
        </Col>

        <Col span={24}>
          <TableCustom
            sticky={{ offsetHeader: -12 }}
            columns={columns}
            dataSource={listData?.ListData}
            loading={loading}
            textEmpty="Không có dữ liệu"
            scroll={{ x: "800px" }}
            pagination={{
              hideOnSinglePage: listData?.TotalCount <= hideOnSinglePage,
              current: pagination?.CurrentPage,
              pageSize: pagination?.PageSize,
              responsive: true,
              total: listData?.TotalCount,
              locale: { items_per_page: "" },
              showSizeChanger: true,
              onChange: (CurrentPage, PageSize) => {
                setPagination(pre => ({
                  ...pre,
                  CurrentPage,
                  PageSize,
                }))
              },
            }}
            rowKey="FeeTransactionID"
            onRow={record => ({
              onClick: () => handleViewDetail(record),
            })}
          />
        </Col>
      </Row>
      <TransactionDetailModal
        open={selectedRecord}
        onCancel={() => setSelectedRecord(null)}
        setLoading={setLoading}
        getList={getList}
        listData={listData}
      />

      {openModalInsertInternal && (
        <FeeInternalModal
          visible={openModalInsertInternal}
          onOk={() => {
            setOpenModalInsertInternal(false)
          }}
          onCancel={() => {
            setOpenModalInsertInternal(false)
          }}
          onSuccess={getList}
        />
      )}
    </SpinCustom>
  )
}

export default ListExpenditure
