import { Col, Form, Input, InputNumber, Row, Select, Typography } from 'antd';
import PropTypes from 'prop-types';
import { useEffect, useState } from 'react';
import CustomModal from 'src/components/Modal/CustomModal';
import ButtonCustom from 'src/components/MyButton/Button';
import notice from 'src/components/Notice';
import SelectCustom from 'src/components/Select/SelectCustom';
import SpinCustom from 'src/components/SpinCustom';
import TitleCustom from 'src/components/TitleCustom';
import FeeManagement from 'src/services/FeeManagement';

const FeeInternalModal = ({ visible, onCancel, onOk, onSuccess }) => {
  const { Text } = Typography;
  const [loading, setLoading] = useState(false)
  const [listAssociation, setListAssociation] = useState([])


  const [form] = Form.useForm();

  // const formatCurrency = (value) =>
  //   `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',');

  // const parseCurrency = (value) =>
  //   value.replace(/,/g, '');


  const getList = async () => {
    try {
      setLoading(true);

      const res = await FeeManagement.getListAssociationWithDueTracking();

      if (res?.isError) return;
      setListAssociation(res?.Object?.Associations || []);
    } catch (error) {
      console.log("error>>getList:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    getList()
  }, [])

  const handleOk = async () => {
    try {
      const values = await form.validateFields();
      const body = { ...values };

      const response = await FeeManagement.postFeeInternal(body);

      if (response?.isOk) {
        notice({ msg: "Khoản phí đã được tạo." });
        onOk?.(response.data);
        onSuccess?.();
        form.resetFields();
        await getList();
      } else {
        notice({ msg: "Tạo khoản phí thất bại!", isSuccess: false });
      }
    } catch (error) {
      const errorMessage =
        error?.response?.data?.message || "Đã xảy ra lỗi khi tạo khoản phí!";
      console.error("Submission failed:", error);
      notice({ msg: errorMessage, isSuccess: false });
    }
  };

  const handleCancel = () => {
    form.resetFields();
    onCancel();
  };

  return (
    <SpinCustom spinning={loading}>
      <CustomModal
        visible={visible}
        onCancel={handleCancel}
        footer={null}
        width={700}
        className="fee-modal"
      >
        <div className="form-container">
          <TitleCustom level={3} className="mb-4">Tạo Khoản Chi Nội Bộ</TitleCustom>

          <Form form={form} layout="vertical" className="fee-form">
            <Form.Item
              label="Mô Tả"
              name="Note"
              className='mt-6'
              rules={[
                { required: true, message: 'Vui lòng nhập mô tả!' },
                { max: 200, message: 'Mô tả không được vượt quá 200 ký tự!' },
              ]}
            >
              <Input.TextArea
                rows={4}
                placeholder="Nhập mô tả giao dịch"
                className="rounded-md"
              />
            </Form.Item>

            <Row gutter={16}>
              <Col span={12}>
                <Form.Item
                  label="Số Tiền"
                  name="Amount"
                  rules={[
                    { required: true },
                    {
                      validator: (_, value) => {
                        if (value === undefined || isNaN(value) || Number(value) <= 0) {
                          return Promise.reject(new Error('Số tiền phải là số dương!'));
                        }
                        if (Number(value) > 2000000000) {
                          return Promise.reject(new Error('Số tiền không được vượt quá 2,000,000,000!'));
                        }
                        return Promise.resolve();
                      }
                    }
                  ]}
                >
                  <InputNumber
                    style={{ width: '100%' }}
                    placeholder="VD: 1,000,000"
                    className="rounded-md"
                    formatter={(value) =>
                      value ? value.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',') : ''
                    }
                    parser={(value) => value.replace(/,/g, '')}
                    suffix="VND"
                  />
                </Form.Item>
              </Col>

              <Col span={12}>
                <Form.Item
                  label="Chi Hội Nhận/Gửi"
                  name="EntityID"
                  rules={[{ required: true, message: 'Vui lòng chọn chi hội!' }]}
                >
                  <SelectCustom placeholder="Chọn chi hội" className="rounded-md w-full">
                    {listAssociation.map((association) => (
                      <Select.Option
                        key={association.AssociationID}
                        value={association.AssociationID}
                      >
                        {association.AssociationName}
                      </Select.Option>
                    ))}
                  </SelectCustom>
                </Form.Item>
              </Col>
            </Row>

            <Row gutter={16}>
              <Col span={12}>
                <div style={{ marginBottom: 24 }}>
                  <Text strong>Phạm Vi Giao Dịch: </Text>
                  <Text >Nội Bộ</Text>
                </div>
              </Col>
              <Col span={12}>
                {/* Giá trị form thực tế */}
                <Form.Item name="FeeType" initialValue="2" hidden>
                  <Input />
                </Form.Item>

                {/* Hiển thị văn bản thay vì input */}
                <div style={{ marginBottom: 24 }}>
                  <Text strong>Loại Giao Dịch: </Text>
                  <Text >Chi</Text>
                </div>
              </Col>
            </Row>

            <Row gutter={16} justify="end" className="mt-6">
              <Col>
                <ButtonCustom className="w-[120px] rounded-md" onClick={handleCancel}>
                  Quay Lại
                </ButtonCustom>
              </Col>
              <Col>
                <ButtonCustom className="w-[120px] rounded-md" onClick={handleOk}>
                  Tạo
                </ButtonCustom>
              </Col>
            </Row>
          </Form>
        </div>
      </CustomModal>
    </SpinCustom>
  );
};

FeeInternalModal.propTypes = {
  visible: PropTypes.bool.isRequired,
  onCancel: PropTypes.func.isRequired,
  onOk: PropTypes.func.isRequired,
  onSuccess: PropTypes.bool.isRequired,
};

export default FeeInternalModal;
