import { Descriptions, Tag } from "antd";
import dayjs from "dayjs";
import PropTypes from "prop-types";
import CustomModal from "src/components/Modal/CustomModal";
import {
  NumberOutlined,
  FileTextOutlined,
  CalendarOutlined,
  DollarCircleOutlined,
  SendOutlined,
  CheckCircleOutlined,
  CloseCircleOutlined,
  InfoCircleOutlined,
} from "@ant-design/icons";
import ButtonCustom from "src/components/MyButton/Button";
import CB1 from "src/components/Modal/CB1";
import FeeManagement from "src/services/FeeManagement";
import notice from "src/components/Notice";

const TransactionDetailModal = ({ open, onCancel, setLoading, getList, listData }) => {
  console.log("..: ", listData)
  const data = open;
  if (!data) return null;

  const {
    FeeCode,
    Note,
    CreateDate,
    SenderName,
    ReceiverName,
    Amount,
    FeeType,
    FeeStatus,
  } = data;

  const formatCurrency = (amount) => {
    if (typeof amount !== "number") {
      amount = Number(amount);
      if (isNaN(amount)) return "0";
    }
    return amount.toLocaleString("vi-VN");
  };

  const renderAmount = () => {
    const color = FeeType === 2 ? "#cf1322" : "#3f8600";
    const sign = FeeType === 2 ? "-" : "+";
    return (
      <span style={{ color, fontWeight: 600, fontSize: 18 }}>
        {sign} {formatCurrency(Amount)} đ
      </span>
    );
  };

  const renderStatus = () => {
    switch (FeeStatus) {
      case 1:
        return <Tag color="orange"><InfoCircleOutlined /> Đang xử lý</Tag>;
      case 2:
        return <Tag color="green"><CheckCircleOutlined /> Đã xác nhận</Tag>;
      default:
        return <Tag color="red"><CloseCircleOutlined /> Từ chối</Tag>;
    }
  };

  const handleApprove = async (record, close) => {
    try {
      setLoading(true);
      const res = await FeeManagement.postChangeFeeStatus({
        feeTransactionID: record.FeeTransactionID,
        feeStatus: 2,
      });
      if (res?.isOk) {
        notice({ msg: "Khoản phí đã được duyệt." });
        await getList();
        onCancel();
      } else {
        notice({ msg: "Duyệt khoản phí thất bại!", isSuccess: false });
      }
    } catch (error) {
      console.error("Duyệt lỗi:", error);
      notice({ msg: "Có lỗi xảy ra khi duyệt!", isSuccess: false });
    } finally {
      setLoading(false);
      close();
    }
  };

  const handleReject = async (record, close) => {
    try {
      setLoading(true);
      const res = await FeeManagement.postChangeFeeStatus({
        feeTransactionID: record.FeeTransactionID,
        feeStatus: 3,
      });
      if (res?.isOk) {
        notice({ msg: "Khoản phí đã bị từ chối." });
        await getList();
        onCancel();
      } else {
        notice({ msg: "Từ chối khoản phí thất bại!", isSuccess: false });
      }
    } catch (error) {
      console.error("Từ chối lỗi:", error);
      notice({ msg: "Có lỗi xảy ra khi từ chối!", isSuccess: false });
    } finally {
      setLoading(false);
      close();
    }
  };

  const handleDelete = async (record, close) => {
    try {
      setLoading(true);
      const res = await FeeManagement.deleteFeeTransaction({
        FeeTransactionID: record.FeeTransactionID,
      });

      if (res?.isOk) {
        notice({ msg: "Xóa giao dịch thành công." });
        await getList();
        onCancel();
      } else {
        console.error("Chi tiết lỗi:", res);
        notice({
          msg: res?.messages?.[0] || "Xóa giao dịch thất bại!",
          isSuccess: false,
        });
      }
    } catch (error) {
      console.error("Lỗi khi xóa giao dịch:", error);
      notice({ msg: "Đã xảy ra lỗi khi xóa giao dịch!", isSuccess: false });
    } finally {
      setLoading(false);
      close();
    }
  };


  const renderDate = () => {
    if (!CreateDate || CreateDate.startsWith("0001-01-01")) {
      return "--";
    }
    return dayjs(CreateDate).format("DD/MM/YYYY");
  };

  return (
    <CustomModal
      title="Chi tiết giao dịch"
      open={!!open}
      onCancel={onCancel}
      footer={null}
      centered
      width={600}
    >
      <Descriptions
        bordered
        column={1}
        labelStyle={{ fontWeight: "bold", background: "#f0f2f5" }}
        contentStyle={{ background: "#ffffff" }}
      >
        <Descriptions.Item label={<><NumberOutlined /> Mã Giao Dịch</>}>
          {FeeCode}
        </Descriptions.Item>

        <Descriptions.Item label={<><FileTextOutlined /> Mô Tả</>}>
          {Note || "--"}
        </Descriptions.Item>

        <Descriptions.Item label={<><CalendarOutlined /> Ngày Tạo</>}>
          {renderDate()}
        </Descriptions.Item>

        <Descriptions.Item label={<><SendOutlined /> Đơn vị gửi</>}>
          {SenderName}
        </Descriptions.Item>

        <Descriptions.Item label={<><SendOutlined /> Đơn vị nhận</>}>
          {ReceiverName}
        </Descriptions.Item>

        <Descriptions.Item label={<><DollarCircleOutlined /> Số Tiền</>}>
          {renderAmount()}
        </Descriptions.Item>

        <Descriptions.Item label={<><InfoCircleOutlined /> Trạng Thái</>}>
          {renderStatus()}
        </Descriptions.Item>
      </Descriptions>

      {FeeStatus === 1 && (
        <div
          style={{
            display: "flex",
            gap: 8,
            marginTop: 16,
            justifyContent: "flex-end",
          }}
        >
          {listData?.ButtonShow?.IsUpdateStatus && (
            <ButtonCustom
              onClick={(e) => {
                e.stopPropagation();
                CB1({
                  title: "Bạn có chắc chắn muốn duyệt khoản phí này không?",
                  icon: "signSuccess",
                  okText: "Đồng ý",
                  onOk: (close) => handleApprove(data, close),
                });
              }}
            >
              Xác nhận
            </ButtonCustom>
          )}

          {listData?.ButtonShow?.IsUpdateStatus && (
            <ButtonCustom
              onClick={(e) => {
                e.stopPropagation();
                CB1({
                  title: "Bạn có chắc chắn muốn từ chối khoản phí này không?",
                  icon: "cancel",
                  okText: "Từ chối",
                  onOk: (close) => handleReject(data, close),
                });
              }}
            >
              Từ chối
            </ButtonCustom>
          )}

          {listData?.ButtonShow?.IsDelete && (
            <ButtonCustom
              onClick={(e) => {
                e.stopPropagation();
                CB1({
                  title: "Bạn có chắc chắn muốn xóa bản ghi này không?",
                  icon: "warning",
                  okText: "Xóa",
                  onOk: async (close) => handleDelete(data, close),
                });
              }}
            >
              Xóa
            </ButtonCustom>
          )}
        </div>
      )}
    </CustomModal>
  );
};

TransactionDetailModal.propTypes = {
  open: PropTypes.object,
  onCancel: PropTypes.func.isRequired,
  setLoading: PropTypes.func.isRequired,
  getList: PropTypes.func.isRequired,
  listData: PropTypes.object,
};


export default TransactionDetailModal;
